fn bytemuck_cast(data: &[f32]) -> &[u8] {
    unsafe { std::slice::from_raw_parts(data.as_ptr() as *const u8, data.len() * 4) }
}

fn bytemuck_cast_mut(data: &mut [f32]) -> &mut [u8] {
    unsafe { std::slice::from_raw_parts_mut(data.as_mut_ptr() as *mut u8, data.len() * 4) }
}

fn u32_bytes(data: &[u32]) -> &[u8] {
    unsafe { std::slice::from_raw_parts(data.as_ptr() as *const u8, std::mem::size_of_val(data)) }
}

fn quant_bytes_per_row(cols: usize, quant: QuantType) -> usize {
    (cols / quant.block_elements()) * quant.block_bytes()
}

pub(crate) fn gdn_fullpath_gemv_dispatches(
    seq_len: usize,
    alpha_quantized: bool,
    beta_quantized: bool,
) -> Option<usize> {
    let projections = 6 + usize::from(alpha_quantized) + usize::from(beta_quantized);
    seq_len.checked_mul(projections)
}

pub(crate) fn embed_lookup_row_bytes(hidden: u32, quant: QuantType) -> Result<usize, String> {
    let block_elements = quant.block_elements() as u32;
    if hidden == 0 || !hidden.is_multiple_of(block_elements) {
        return Err(format!(
            "embed_lookup: {quant:?} hidden {hidden} must be a positive multiple of {block_elements}",
        ));
    }
    Ok(quant_bytes_per_row(hidden as usize, quant))
}

pub(crate) fn logit_argmax_row_bytes(
    hidden: u32,
    output_quant: QuantType,
) -> Result<usize, String> {
    let block_elements = output_quant.block_elements() as u32;
    if hidden == 0 || !hidden.is_multiple_of(block_elements) {
        return Err(format!(
            "logit_argmax: {output_quant:?} hidden {hidden} must be a positive multiple of {block_elements}",
        ));
    }
    Ok(quant_bytes_per_row(hidden as usize, output_quant))
}

fn output_table_resident_payload(
    bytes: &[u8],
    output_quant: QuantType,
    vocab: u32,
    hidden: u32,
) -> Result<Vec<u8>, String> {
    let row_bytes = logit_argmax_row_bytes(hidden, output_quant)?;
    let expected_table = (vocab as usize) * row_bytes;
    if bytes.len() != expected_table {
        return Err(format!(
            "output_table_resident_payload: table len {} != vocab*row_bytes ({}) for {:?}",
            bytes.len(),
            expected_table,
            output_quant
        ));
    }
    Ok(bytes.to_vec())
}

fn q8_chunked_output_enabled() -> bool {
    std::env::var_os("RNB_VULKAN_Q8_OUTPUT_CHUNKED").is_some()
}

// Q8_0 output rows must fan out across the GPU. The legacy row-major argmax
// dispatches a single workgroup for the entire vocabulary and is diagnostic-only.
// Keep `=0` as an explicit comparison/rollback path.
fn q8_soa_output_enabled() -> Result<bool, String> {
    match std::env::var("RNB_VULKAN_Q8_OUTPUT_SOA") {
        Ok(raw) => {
            let value = raw.trim();
            Ok(!(value == "0"
                || value.eq_ignore_ascii_case("false")
                || value.eq_ignore_ascii_case("off")
                || value.eq_ignore_ascii_case("no")))
        }
        Err(std::env::VarError::NotPresent) => Ok(true),
        Err(e) => Err(format!(
            "RNB_VULKAN_Q8_OUTPUT_SOA is not valid unicode: {e}"
        )),
    }
}

fn q8_soa_device_local_enabled() -> bool {
    std::env::var_os("RNB_VULKAN_Q8_OUTPUT_SOA_DEVICE").is_some()
}

fn debug_output_topk() -> Option<usize> {
    std::env::var("RNB_VULKAN_DUMP_OUTPUT_TOPK")
        .ok()
        .and_then(|raw| raw.parse::<usize>().ok())
        .filter(|&k| k > 0)
}

fn debug_output_ids() -> Vec<u32> {
    std::env::var("RNB_VULKAN_DUMP_OUTPUT_IDS")
        .ok()
        .map(|raw| {
            raw.split([';', ','])
                .filter_map(|part| {
                    let trimmed = part.trim();
                    (!trimmed.is_empty())
                        .then(|| trimmed.parse::<u32>().ok())
                        .flatten()
                })
                .collect()
        })
        .unwrap_or_default()
}

