#[derive(Clone, Copy, Debug, Default)]
pub struct RuntimeCounters {
    pub submits: u64,
    pub upload_bytes: u64,
    pub download_bytes: u64,
    pub materializations: u64,
    pub attention_fan_in_copies: u64,
    pub host_tensor_roundtrip_bytes: u64,
}

impl RuntimeCounters {
    pub fn record_host_tensor_roundtrip(&mut self, download_bytes: u64, upload_bytes: u64) {
        self.download_bytes += download_bytes;
        self.upload_bytes += upload_bytes;
        self.host_tensor_roundtrip_bytes += download_bytes + upload_bytes;
        self.materializations += 1;
    }

    pub fn has_forbidden_fullpath_cpu_escape(&self) -> bool {
        self.host_tensor_roundtrip_bytes > 0 || self.materializations > 0
    }
}

/// Input source for `record_gemv_window`. Two layouts are common in the
/// recording API:
///
/// - `Strided`: a single contiguous input buffer where token `t` lives at
///   `offset + t * stride_bytes`. Used by `gemv_batch`-style fast paths and
///   any caller that has already packed inputs back-to-back.
/// - `PerToken`: each token's input lives in its own dedicated buffer at
///   offset 0 (e.g. the rms_norm or silu_mul output buffers in the FFN
///   chain). `bytes_per_token` is the per-token input length used as the
///   bind range.
///
/// Push-constants, descriptor binding mechanics and dispatch are identical
/// in both cases; only the input-side `(buf, offset, range)` triple changes
/// per token.
pub(crate) enum GemvInput<'a> {
    Strided {
        buf: &'a GpuBuffer,
        offset: u64,
        stride_bytes: u64,
    },
    PerToken {
        bufs: &'a [&'a GpuBuffer],
        bytes_per_token: u64,
    },
}

/// Per-layer attention pipeline composition input. Bundles the buffers,
/// weights, dimensions and per-pipeline `set_idx_*_base` values that
/// `VulkanLayerGemv::record_attention_layer_fullpath` needs. Caller
/// (Task 8d `full_path::run_prefill`) is responsible for:
/// - allocating the hidden ping-pong buffers and per-token intermediate
///   slot buffers
/// - pre-uploading all weight buffers via `cache.get_or_upload`
/// - ensuring KV mirror buffers exist for `(layer_idx, kvh)` (call sites
///   that already use `attention_block_window_for_layer` go through
///   `ensure_attention_cache_layer_buffers` — fullpath consumers must do
///   the same before calling this recorder)
/// - cmd buffer begin/end, submit, fence, host-side reads
/// - threading `set_idx_*_base` so subsequent layers in the same submit
///   don't collide; this recorder validates each pipeline's window against
///   `MAX_BATCH_OUTPUTS` and returns Err on overflow
#[allow(dead_code)] // wired by Task 8d's full_path::run_prefill
pub(crate) struct AttentionLayerFullpathInput<'a> {
    // ----- topology -----
    pub layer_idx: usize,
    /// hidden_in[t] lives at `hidden_in_offset + t * hidden_dim * 4` in
    /// `hidden_in_buf`. Residual stream coming into the layer.
    pub hidden_in_buf: &'a GpuBuffer,
    pub hidden_in_offset: u64,
    /// hidden_out[t] is written at `hidden_out_offset + t * hidden_dim * 4`
    /// in `hidden_out_buf`. After this recorder it holds the layer output
    /// (post attn + ffn residual).
    pub hidden_out_buf: &'a GpuBuffer,
    pub hidden_out_offset: u64,
    // ----- contiguous strided staging buffers (mv26-task10b-1 retro-fix) -----
    //
    // mv24 used per-token disjoint GpuBuffer slices for every intermediate
    // (norm_attn / q / attn / o_proj_out / gate / up / down / norm_ffn),
    // alternating with per-token→strided `vkCmdCopyBuffer` pack stages to
    // bridge per-token ↔ strided. For Qwen3.5 0.8B prefill (1140 tokens * 24
    // layers * 14 heads) that produced an O(16K) GpuBuffer alloc storm.
    //
    // mv26-task10b-1 retro-fits the layer-fullpath chain to feed the
    // already-strided primitives (qkv_window strided input, attention_decode
    // q_buf, ffn_chain GEMV strided input) directly with strided writes from
    // the prior stage, eliminating all four pack-bridge stages. Each strided
    // buffer below is shared across all tokens of a single layer;
    // mv26-task10b-3 hoists these to a startup-alloc pool. mv1-19
    // partial-offload's per-token API is left untouched (new
    // `record_*_strided` variants live alongside the originals).
    /// rms_norm(attn) output. Capacity must be at least
    /// `seq_len * hidden_dim * 4` bytes. Layout: token `t` at
    /// `t * hidden_dim * 4`.
    pub norm_attn_strided_buf: &'a GpuBuffer,
    /// Q projection output. Capacity must be at least
    /// `seq_len * num_heads * head_dim * 4` bytes (= `seq_len * q_dim * 4`).
    /// Layout matches what `attention_decode` expects:
    /// `(t * num_heads + h) * head_dim`.
    pub q_strided_buf: &'a GpuBuffer,
    /// Per-(token, head) attention output. Capacity must be at least
    /// `seq_len * num_heads * head_dim * 4` bytes. Layout (t-major, matches
    /// the o_proj GEMV strided input convention shared with mv1-19
    /// partial-offload): `(t * num_heads + h) * head_dim`.
    pub o_proj_input_strided_buf: &'a GpuBuffer,
    /// o_proj output, used as the FFN residual. Capacity must be at least
    /// `seq_len * hidden_dim * 4` bytes. Layout: `t * hidden_dim`.
    pub o_proj_out_strided_buf: &'a GpuBuffer,
    /// rms_norm(ffn) output (= ffn_chain norm step destination). Capacity
    /// must be at least `seq_len * hidden_dim * 4` bytes. Layout:
    /// `t * hidden_dim`.
    pub norm_ffn_strided_buf: &'a GpuBuffer,
    /// FFN gate GEMV output, then in-place silu·up result, then down GEMV
    /// input. Capacity must be at least `seq_len * ffn_inner * 4` bytes.
    /// Layout: `t * ffn_inner`.
    pub gate_strided_buf: &'a GpuBuffer,
    /// FFN up GEMV output (read-only by silu_mul). Capacity must be at least
    /// `seq_len * ffn_inner * 4` bytes. Layout: `t * ffn_inner`.
    pub up_strided_buf: &'a GpuBuffer,
    /// FFN down GEMV output (added back into accumulator at the chain tail).
    /// Capacity must be at least `seq_len * hidden_dim * 4` bytes. Layout:
    /// `t * hidden_dim`.
    pub down_strided_buf: &'a GpuBuffer,
    // ----- weights (pre-uploaded GPU handles) -----
    pub attn_norm_buf: &'a GpuBuffer,
    pub attn_norm_size: u64,
    pub q_weight_buf: &'a GpuBuffer,
    pub q_weight_size: u64,
    pub q_rows: u32,
    pub q_cols: u32,
    pub q_quant: QuantType,
    pub q_bias_buf: Option<&'a GpuBuffer>,
    pub q_bias_size: u64,
    pub q_norm_buf: Option<&'a GpuBuffer>,
    pub q_norm_size: u64,
    pub k_weight_bufs: &'a [&'a GpuBuffer],
    pub k_weight_size: u64,
    pub k_quant: QuantType,
    pub k_bias_buf: Option<&'a GpuBuffer>,
    pub k_bias_size: u64,
    pub k_norm_buf: Option<&'a GpuBuffer>,
    pub k_norm_size: u64,
    pub v_weight_bufs: &'a [&'a GpuBuffer],
    pub v_weight_size: u64,
    pub v_quant: QuantType,
    pub v_bias_buf: Option<&'a GpuBuffer>,
    pub v_bias_size: u64,
    pub o_weight_buf: &'a GpuBuffer,
    pub o_weight_size: u64,
    pub o_quant: QuantType,
    pub ffn_norm_buf: &'a GpuBuffer,
    pub ffn_norm_size: u64,
    pub gate_weight_buf: &'a GpuBuffer,
    pub gate_weight_size: u64,
    pub gate_quant: QuantType,
    pub up_weight_buf: &'a GpuBuffer,
    pub up_weight_size: u64,
    pub up_quant: QuantType,
    pub down_weight_buf: &'a GpuBuffer,
    pub down_weight_size: u64,
    pub down_quant: QuantType,
    // ----- dims -----
    pub seq_len: u32,
    pub hidden_dim: u32,
    pub num_heads: u32,
    pub num_kv_heads: u32,
    pub head_dim: u32,
    pub ffn_inner: u32,
    pub norm_eps: f32,
    pub pos_start: u32,
    /// RoPE base frequency (rope_theta from model metadata, e.g. 10000.0 for Qwen3.5).
    /// NEOX rotation is applied to both Q and each K kv-head slice after the
    /// q_window GEMV step. V is never rotated (standard transformer convention).
    pub base_freq: f32,
    /// Number of per-head dimensions to rotate. `0` means full `head_dim`.
    pub rope_dim: u32,
    /// True for NEOX/Gemma-style split-half pairing; false for adjacent-pair RoPE.
    pub rope_neox: bool,
    // ----- per-pipeline descriptor-set bases -----
    // Each cached pipeline has its own pool of `MAX_BATCH_OUTPUTS` sets.
    // The caller threads these per-pipeline indices across the layer loop so
    // dispatches inside this layer do not clobber sets from prior layers in
    // the same cmd buffer.
    pub set_idx_norm_base: usize,
    pub set_idx_q_base: usize,
    pub set_idx_k_base: usize,
    pub set_idx_v_base: usize,
    pub set_idx_attn_base: usize,
    pub set_idx_o_base: usize,
    pub set_idx_silu_base: usize,
    pub set_idx_add_base: usize,
    pub set_idx_gate_base: usize,
    pub set_idx_bias_base: usize,
    pub set_idx_up_base: usize,
    pub set_idx_down_base: usize,
    /// Descriptor-set base for the Q RoPE dispatch (1 set per layer).
    pub set_idx_rope_q_base: usize,
    /// Descriptor-set base for the per-kv-head K RoPE dispatches
    /// (num_kv_heads sets per layer).
    pub set_idx_rope_k_base: usize,
}

