/// Per-layer descriptor-set consumption tally returned by
/// `record_attention_layer_fullpath`. Sums dispatches per cached pipeline so
/// the caller can advance `set_idx_*_base` for the next layer and detect
/// when a `MAX_BATCH_OUTPUTS` budget needs to be split across multiple
/// submits.
#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct AttentionLayerSetsConsumed {
    pub norm: usize,
    pub q: usize,
    pub k: usize,
    pub v: usize,
    pub attn: usize,
    pub o: usize,
    pub gate: usize,
    pub up: usize,
    pub down: usize,
    pub silu: usize,
    pub add: usize,
    pub bias: usize,
    /// mv24: NEOX RoPE dispatches for Q (always 1 per layer).
    pub rope_q: usize,
    /// mv24: NEOX RoPE dispatches for K (num_kv_heads per layer).
    pub rope_k: usize,
}

impl AttentionLayerSetsConsumed {
    pub(crate) fn attention_fullpath(
        seq_len: usize,
        num_heads: usize,
        num_kv_heads: usize,
        has_q_norm: bool,
        has_k_norm: bool,
        has_q_bias: bool,
        has_k_bias: bool,
        has_v_bias: bool,
    ) -> Option<Self> {
        let q_norm_dispatches = if has_q_norm {
            seq_len.checked_mul(num_heads)?
        } else {
            0
        };
        let k_norm_dispatches = if has_k_norm {
            seq_len.checked_mul(num_kv_heads)?
        } else {
            0
        };
        let gemv_dispatches = num_kv_heads
            .checked_mul(2)?
            .checked_add(5)?
            .checked_mul(seq_len)?;
        let bias_dispatches = usize::from(has_q_bias)
            .checked_add(num_kv_heads.checked_mul(usize::from(has_k_bias))?)?
            .checked_add(num_kv_heads.checked_mul(usize::from(has_v_bias))?)?;

        Some(Self {
            norm: seq_len
                .checked_mul(2)?
                .checked_add(q_norm_dispatches)?
                .checked_add(k_norm_dispatches)?,
            q: gemv_dispatches,
            k: gemv_dispatches,
            v: gemv_dispatches,
            attn: seq_len.checked_mul(num_heads)?,
            o: gemv_dispatches,
            gate: gemv_dispatches,
            up: gemv_dispatches,
            down: gemv_dispatches,
            silu: seq_len,
            add: seq_len.checked_mul(2)?,
            bias: bias_dispatches,
            rope_q: 1,
            rope_k: num_kv_heads,
        })
    }

    pub(crate) fn gdn_fullpath(
        seq_len: usize,
        alpha_quantized: bool,
        beta_quantized: bool,
    ) -> Option<Self> {
        Some(Self {
            norm: seq_len.checked_mul(2)?,
            q: gdn_fullpath_gemv_dispatches(seq_len, alpha_quantized, beta_quantized)?,
            k: seq_len,
            v: seq_len.checked_mul(2)?,
            attn: seq_len,
            o: 0,
            gate: 0,
            up: 0,
            down: 0,
            silu: seq_len,
            add: seq_len.checked_mul(2)?,
            bias: 0,
            rope_q: 0,
            rope_k: 0,
        })
    }

    /// Maximum sets consumed in a single pipeline pool — the actual binding
    /// pressure since each pipeline has its own pool of size
    /// `MAX_BATCH_OUTPUTS`.
    ///
    /// Note: `rope_q` and `rope_k` share the same cached pipeline
    /// (`pipeline_rope_apply`), so their combined total is the pressure on
    /// that pool: `rope_q + rope_k`.
    #[allow(dead_code)]
    pub fn max_per_pipeline(&self) -> usize {
        *[
            self.norm,
            self.q,
            self.k,
            self.v,
            self.attn,
            self.o,
            self.gate,
            self.up,
            self.down,
            self.silu,
            self.add,
            self.bias,
            self.rope_q + self.rope_k, // shared rope_apply pipeline pool
        ]
        .iter()
        .max()
        .unwrap_or(&0)
    }
}

/// High-level Vulkan GEMV API with weight caching and batch dispatch.
