    /// Lazily build the embedding lookup pipeline for the selected quant.
    unsafe fn ensure_embed_lookup_pipeline(&mut self, quant: QuantType) -> Result<(), String> {
        if !quant.has_soa_kernel() {
            if !self.native_quant_embed_pipelines.contains_key(&quant) {
                let spirv = crate::spirv::emit_native_quant_embed_lookup(quant, LOCAL_SIZE_X)?;
                let pipe = ComputePipeline::new_nbinding(
                    &self.ctx,
                    &spirv,
                    MAX_BATCH_OUTPUTS as u32,
                    EMBED_LOOKUP_NUM_BINDINGS,
                    EMBED_LOOKUP_PUSH_BYTES,
                )?;
                self.native_quant_embed_pipelines.insert(quant, pipe);
            }
            return Ok(());
        }

        let slot = match quant {
            QuantType::Q4K => &mut self.pipeline_embed_lookup_q4,
            QuantType::Q5K => &mut self.pipeline_embed_lookup_q5,
            QuantType::Q6K => &mut self.pipeline_embed_lookup,
            QuantType::Q8_0 => &mut self.pipeline_embed_lookup_q8,
            _ => unreachable!("SoA quant must have a dedicated embedding pipeline"),
        };
        if slot.is_none() {
            let spirv = match quant {
                QuantType::Q4K => crate::spirv::emit_embed_lookup_q4k(LOCAL_SIZE_X),
                QuantType::Q5K => crate::spirv::emit_embed_lookup_q5k(LOCAL_SIZE_X),
                QuantType::Q6K => crate::spirv::builder::emit_embed_lookup_q6k(LOCAL_SIZE_X),
                QuantType::Q8_0 => crate::spirv::emit_embed_lookup_q8_0(LOCAL_SIZE_X),
                _ => unreachable!("SoA quant must have a dedicated embedding shader"),
            };
            let pipe = ComputePipeline::new_nbinding(
                &self.ctx,
                &spirv,
                MAX_BATCH_OUTPUTS as u32,
                EMBED_LOOKUP_NUM_BINDINGS,
                EMBED_LOOKUP_PUSH_BYTES,
            )?;
            *slot = Some(pipe);
        }
        Ok(())
    }

    /// Lazily build the output logit-argmax compute pipeline for the given quant.
    unsafe fn ensure_logit_argmax_pipeline(
        &mut self,
        output_quant: QuantType,
    ) -> Result<(), String> {
        use crate::spirv::builder::emit_logit_argmax_q6k;
        match output_quant {
            QuantType::Q4K => {
                if self.pipeline_logit_argmax_q4.is_none() {
                    let spirv = emit_logit_argmax_q4k(LOGIT_ARGMAX_LOCAL_SIZE);
                    let pipe = ComputePipeline::new_nbinding(
                        &self.ctx,
                        &spirv,
                        MAX_BATCH_OUTPUTS as u32,
                        LOGIT_ARGMAX_NUM_BINDINGS,
                        LOGIT_ARGMAX_PUSH_BYTES,
                    )?;
                    self.pipeline_logit_argmax_q4 = Some(pipe);
                }
            }
            QuantType::Q5K => {
                if self.pipeline_logit_argmax_q5.is_none() {
                    let spirv = emit_logit_argmax_q5k(LOGIT_ARGMAX_LOCAL_SIZE);
                    let pipe = ComputePipeline::new_nbinding(
                        &self.ctx,
                        &spirv,
                        MAX_BATCH_OUTPUTS as u32,
                        LOGIT_ARGMAX_NUM_BINDINGS,
                        LOGIT_ARGMAX_PUSH_BYTES,
                    )?;
                    self.pipeline_logit_argmax_q5 = Some(pipe);
                }
            }
            QuantType::Q6K => {
                if self.pipeline_logit_argmax.is_none() {
                    let spirv = emit_logit_argmax_q6k(LOGIT_ARGMAX_LOCAL_SIZE);
                    let pipe = ComputePipeline::new_nbinding(
                        &self.ctx,
                        &spirv,
                        MAX_BATCH_OUTPUTS as u32,
                        LOGIT_ARGMAX_NUM_BINDINGS,
                        LOGIT_ARGMAX_PUSH_BYTES,
                    )?;
                    self.pipeline_logit_argmax = Some(pipe);
                }
            }
            QuantType::Q8_0 => {
                if self.pipeline_logit_argmax_q8.is_none() {
                    let spirv = emit_logit_argmax_q8_0(LOGIT_ARGMAX_LOCAL_SIZE);
                    let pipe = ComputePipeline::new_nbinding(
                        &self.ctx,
                        &spirv,
                        MAX_BATCH_OUTPUTS as u32,
                        LOGIT_ARGMAX_NUM_BINDINGS,
                        LOGIT_ARGMAX_PUSH_BYTES,
                    )?;
                    self.pipeline_logit_argmax_q8 = Some(pipe);
                }
            }
            other => {
                if !self.native_quant_argmax_pipelines.contains_key(&other) {
                    let spirv = crate::spirv::emit_native_quant_logit_argmax(
                        other,
                        LOGIT_ARGMAX_LOCAL_SIZE,
                    )?;
                    let pipe = ComputePipeline::new_nbinding(
                        &self.ctx,
                        &spirv,
                        MAX_BATCH_OUTPUTS as u32,
                        LOGIT_ARGMAX_NUM_BINDINGS,
                        LOGIT_ARGMAX_PUSH_BYTES,
                    )?;
                    self.native_quant_argmax_pipelines.insert(other, pipe);
                }
            }
        }
        Ok(())
    }

