    /// Thin wrapper over `record_rms_norm_window`. Host-uploads `input_all`
    /// and `norm_weight` to the persistent staging buffers, records per-token
    /// dispatches, barriers compute→HOST_READ, submits and waits, then copies
    /// output_bufs[t] back into `out_all`.
    pub fn rms_norm_window(
        &mut self,
        input_all: &[f32],
        norm_weight: &[f32],
        norm_eps: f32,
        hidden_dim: usize,
        out_all: &mut [f32],
    ) -> Result<(), String> {
        if input_all.len() % hidden_dim != 0 || out_all.len() < input_all.len() {
            return Err("rms_norm_window shape mismatch".into());
        }
        let seq_len = input_all.len() / hidden_dim;
        let hidden_bytes = hidden_dim * 4;
        let norm_wt_bytes = norm_weight.len() * 4;

        if seq_len <= MAX_BATCH_OUTPUTS && input_all.len() <= self.input_capacity {
            // Fast path: single submit covers all tokens.
            unsafe {
                let total_input_bytes = input_all.len() * 4;
                ptr::copy_nonoverlapping(
                    input_all.as_ptr() as *const u8,
                    self.input_mapped_ptr,
                    total_input_bytes,
                );
                self.runtime_counters.upload_bytes += total_input_bytes as u64;
                ptr::copy_nonoverlapping(
                    norm_weight.as_ptr() as *const u8,
                    self.norm_weight_mapped_ptr,
                    norm_wt_bytes,
                );
                self.runtime_counters.upload_bytes += norm_wt_bytes as u64;

                // Capture buffer pointers for the record_* call. record_* takes
                // `&mut self` for pattern-parity but only reads pipeline/ctx;
                // self.input_buf / norm_weight_buf / output_bufs are not touched
                // mutably inside record_*, so re-borrowing through raw pointers
                // is sound.
                let input_buf_ptr = self.input_buf.as_ref().unwrap() as *const GpuBuffer;
                let norm_wt_buf_ptr = self.norm_weight_buf.as_ref().unwrap() as *const GpuBuffer;
                let output_buf_ptrs: Vec<*const GpuBuffer> = (0..seq_len)
                    .map(|t| self.output_bufs[t].as_ref().unwrap() as *const GpuBuffer)
                    .collect();
                let output_refs: Vec<&GpuBuffer> = output_buf_ptrs.iter().map(|p| &**p).collect();

                (self.ctx.vk.reset_command_buffer)(self.command_buffer, 0);
                let begin = VkCommandBufferBeginInfo {
                    s_type: VK_STRUCTURE_TYPE_COMMAND_BUFFER_BEGIN_INFO,
                    p_next: ptr::null(),
                    flags: VK_COMMAND_BUFFER_USAGE_ONE_TIME_SUBMIT_BIT,
                    p_inheritance_info: ptr::null(),
                };
                (self.ctx.vk.begin_command_buffer)(self.command_buffer, &begin);

                let cmdbuf = self.command_buffer;
                if let Err(e) = self.record_rms_norm_window(
                    cmdbuf,
                    0,
                    &*input_buf_ptr,
                    0,
                    hidden_bytes as u64,
                    &*norm_wt_buf_ptr,
                    norm_wt_bytes as u64,
                    &output_refs,
                    seq_len as u32,
                    hidden_dim as u32,
                    norm_eps,
                ) {
                    (self.ctx.vk.end_command_buffer)(self.command_buffer);
                    return Err(e);
                }

                let mut barriers = Vec::with_capacity(seq_len);
                for r in &output_refs {
                    barriers.push(VkBufferMemoryBarrier {
                        s_type: VK_STRUCTURE_TYPE_BUFFER_MEMORY_BARRIER,
                        p_next: ptr::null(),
                        src_access_mask: VK_ACCESS_SHADER_WRITE_BIT,
                        dst_access_mask: VK_ACCESS_HOST_READ_BIT,
                        src_queue_family_index: VK_QUEUE_FAMILY_IGNORED,
                        dst_queue_family_index: VK_QUEUE_FAMILY_IGNORED,
                        buffer: r.buffer,
                        offset: 0,
                        size: VK_WHOLE_SIZE,
                    });
                }
                (self.ctx.vk.cmd_pipeline_barrier)(
                    self.command_buffer,
                    VK_PIPELINE_STAGE_COMPUTE_SHADER_BIT,
                    VK_PIPELINE_STAGE_HOST_BIT,
                    0,
                    0,
                    ptr::null(),
                    barriers.len() as u32,
                    barriers.as_ptr(),
                    0,
                    ptr::null(),
                );
                (self.ctx.vk.end_command_buffer)(self.command_buffer);
                (self.ctx.vk.reset_fences)(self.ctx.device, 1, &self.fence);
                let submit = VkSubmitInfo {
                    s_type: VK_STRUCTURE_TYPE_SUBMIT_INFO,
                    p_next: ptr::null(),
                    wait_semaphore_count: 0,
                    p_wait_semaphores: ptr::null(),
                    p_wait_dst_stage_mask: ptr::null(),
                    command_buffer_count: 1,
                    p_command_buffers: &self.command_buffer,
                    signal_semaphore_count: 0,
                    p_signal_semaphores: ptr::null(),
                };
                (self.ctx.vk.queue_submit)(self.ctx.queue, 1, &submit, self.fence);
                (self.ctx.vk.wait_for_fences)(
                    self.ctx.device,
                    1,
                    &self.fence,
                    1,
                    10_000_000_000u64,
                );
                self.runtime_counters.submits += 1;
                for t in 0..seq_len {
                    ptr::copy_nonoverlapping(
                        self.output_mapped_ptrs[t],
                        out_all[t * hidden_dim..(t + 1) * hidden_dim].as_mut_ptr() as *mut u8,
                        hidden_bytes,
                    );
                    self.runtime_counters.download_bytes += hidden_bytes as u64;
                }
            }
            return Ok(());
        }

        // Fallback: per-token submit (used when seq_len > MAX_BATCH_OUTPUTS or
        // input_all does not fit the persistent staging buffer). Each iteration
        // uploads one token to slot 0, records a single dispatch via
        // `record_rms_norm_window`, barriers, submits and downloads.
        for t in 0..seq_len {
            let input = &input_all[t * hidden_dim..(t + 1) * hidden_dim];
            let out = &mut out_all[t * hidden_dim..(t + 1) * hidden_dim];
            unsafe {
                ptr::copy_nonoverlapping(
                    input.as_ptr() as *const u8,
                    self.input_mapped_ptr,
                    hidden_bytes,
                );
                self.runtime_counters.upload_bytes += hidden_bytes as u64;
                ptr::copy_nonoverlapping(
                    norm_weight.as_ptr() as *const u8,
                    self.norm_weight_mapped_ptr,
                    norm_wt_bytes,
                );
                self.runtime_counters.upload_bytes += norm_wt_bytes as u64;

                let input_buf_ptr = self.input_buf.as_ref().unwrap() as *const GpuBuffer;
                let norm_wt_buf_ptr = self.norm_weight_buf.as_ref().unwrap() as *const GpuBuffer;
                let norm_out_buf_ptr = self.output_bufs[0].as_ref().unwrap() as *const GpuBuffer;
                let output_refs: [&GpuBuffer; 1] = [&*norm_out_buf_ptr];
                let barrier_buf = (*norm_out_buf_ptr).buffer;

                (self.ctx.vk.reset_command_buffer)(self.command_buffer, 0);
                let begin = VkCommandBufferBeginInfo {
                    s_type: VK_STRUCTURE_TYPE_COMMAND_BUFFER_BEGIN_INFO,
                    p_next: ptr::null(),
                    flags: VK_COMMAND_BUFFER_USAGE_ONE_TIME_SUBMIT_BIT,
                    p_inheritance_info: ptr::null(),
                };
                (self.ctx.vk.begin_command_buffer)(self.command_buffer, &begin);

                let cmdbuf = self.command_buffer;
                if let Err(e) = self.record_rms_norm_window(
                    cmdbuf,
                    0,
                    &*input_buf_ptr,
                    0,
                    0, // single token per submit, so no per-token offset stride
                    &*norm_wt_buf_ptr,
                    norm_wt_bytes as u64,
                    &output_refs,
                    1,
                    hidden_dim as u32,
                    norm_eps,
                ) {
                    (self.ctx.vk.end_command_buffer)(self.command_buffer);
                    return Err(e);
                }

                let barrier = VkBufferMemoryBarrier {
                    s_type: VK_STRUCTURE_TYPE_BUFFER_MEMORY_BARRIER,
                    p_next: ptr::null(),
                    src_access_mask: VK_ACCESS_SHADER_WRITE_BIT,
                    dst_access_mask: VK_ACCESS_HOST_READ_BIT,
                    src_queue_family_index: VK_QUEUE_FAMILY_IGNORED,
                    dst_queue_family_index: VK_QUEUE_FAMILY_IGNORED,
                    buffer: barrier_buf,
                    offset: 0,
                    size: VK_WHOLE_SIZE,
                };
                (self.ctx.vk.cmd_pipeline_barrier)(
                    self.command_buffer,
                    VK_PIPELINE_STAGE_COMPUTE_SHADER_BIT,
                    VK_PIPELINE_STAGE_HOST_BIT,
                    0,
                    0,
                    ptr::null(),
                    1,
                    &barrier,
                    0,
                    ptr::null(),
                );
                (self.ctx.vk.end_command_buffer)(self.command_buffer);
                (self.ctx.vk.reset_fences)(self.ctx.device, 1, &self.fence);
                let submit = VkSubmitInfo {
                    s_type: VK_STRUCTURE_TYPE_SUBMIT_INFO,
                    p_next: ptr::null(),
                    wait_semaphore_count: 0,
                    p_wait_semaphores: ptr::null(),
                    p_wait_dst_stage_mask: ptr::null(),
                    command_buffer_count: 1,
                    p_command_buffers: &self.command_buffer,
                    signal_semaphore_count: 0,
                    p_signal_semaphores: ptr::null(),
                };
                (self.ctx.vk.queue_submit)(self.ctx.queue, 1, &submit, self.fence);
                (self.ctx.vk.wait_for_fences)(
                    self.ctx.device,
                    1,
                    &self.fence,
                    1,
                    10_000_000_000u64,
                );
                self.runtime_counters.submits += 1;
                ptr::copy_nonoverlapping(
                    self.output_mapped_ptrs[0],
                    out.as_mut_ptr() as *mut u8,
                    hidden_bytes,
                );
                self.runtime_counters.download_bytes += hidden_bytes as u64;
            }
        }
        Ok(())
    }

    pub fn self_test_rms_norm_window(&mut self) -> Result<(), String> {
        let hidden_dim = 4usize;
        let input = vec![0.25f32, -0.5, 0.75, 1.0, -1.25, 1.5, -1.75, 2.0];
        let norm_weight = vec![1.0f32; hidden_dim];
        let mut out = vec![0.0f32; input.len()];
        self.rms_norm_window(&input, &norm_weight, 1e-5, hidden_dim, &mut out)?;
        for t in 0..2 {
            let slice = &input[t * hidden_dim..(t + 1) * hidden_dim];
            let mean_sq = slice.iter().map(|x| x * x).sum::<f32>() / hidden_dim as f32;
            let inv_rms = 1.0 / (mean_sq + 1e-5).sqrt();
            for i in 0..hidden_dim {
                let expected = slice[i] * inv_rms;
                let got = out[t * hidden_dim + i];
                if (got - expected).abs() > 1e-4 {
                    return Err(format!(
                        "rms_norm_window mismatch t={} i={} got={} expected={}",
                        t, i, got, expected
                    ));
                }
            }
        }
        Ok(())
    }

