    unsafe fn ensure_attention_buffers(
        &mut self,
        q_bytes: usize,
        kv_bytes: usize,
        host_vis: VkFlags,
    ) -> Result<(), String> {
        if self.attention_q_capacity < q_bytes {
            if let Some(ref buf) = self.attention_q_buf {
                self.ctx.unmap_buffer(buf);
            }
            if let Some(buf) = self.attention_q_buf.take() {
                self.ctx.destroy_buffer(buf);
            }
            let buf = self.ctx.create_buffer(
                q_bytes as u64,
                VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
                host_vis,
            )?;
            self.attention_q_mapped_ptr = self.ctx.map_buffer_persistent(&buf)?;
            self.attention_q_capacity = q_bytes;
            self.attention_q_buf = Some(buf);
        }
        if self.attention_k_capacity < kv_bytes {
            if let Some(ref buf) = self.attention_k_buf {
                self.ctx.unmap_buffer(buf);
            }
            if let Some(buf) = self.attention_k_buf.take() {
                self.ctx.destroy_buffer(buf);
            }
            let buf = self.ctx.create_buffer(
                kv_bytes as u64,
                VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
                host_vis,
            )?;
            self.attention_k_mapped_ptr = self.ctx.map_buffer_persistent(&buf)?;
            self.attention_k_capacity = kv_bytes;
            self.attention_k_buf = Some(buf);
        }
        if self.attention_v_capacity < kv_bytes {
            if let Some(ref buf) = self.attention_v_buf {
                self.ctx.unmap_buffer(buf);
            }
            if let Some(buf) = self.attention_v_buf.take() {
                self.ctx.destroy_buffer(buf);
            }
            let buf = self.ctx.create_buffer(
                kv_bytes as u64,
                VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
                host_vis,
            )?;
            self.attention_v_mapped_ptr = self.ctx.map_buffer_persistent(&buf)?;
            self.attention_v_capacity = kv_bytes;
            self.attention_v_buf = Some(buf);
        }
        if self.attention_out_capacity < q_bytes {
            if let Some(ref buf) = self.attention_out_buf {
                self.ctx.unmap_buffer(buf);
            }
            if let Some(buf) = self.attention_out_buf.take() {
                self.ctx.destroy_buffer(buf);
            }
            let buf = self.ctx.create_buffer(
                q_bytes as u64,
                VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
                host_vis,
            )?;
            self.attention_out_mapped_ptr = self.ctx.map_buffer_persistent(&buf)? as *const u8;
            self.attention_out_capacity = q_bytes;
            self.attention_out_buf = Some(buf);
        }
        Ok(())
    }

    unsafe fn ensure_prefill_hidden_buffer(
        &mut self,
        bytes: usize,
        host_vis: VkFlags,
    ) -> Result<(), String> {
        if self.prefill_hidden_capacity < bytes {
            if let Some(ref buf) = self.prefill_hidden_buf {
                self.ctx.unmap_buffer(buf);
            }
            if let Some(buf) = self.prefill_hidden_buf.take() {
                self.ctx.destroy_buffer(buf);
            }
            let buf = self.ctx.create_buffer(
                bytes as u64,
                VK_BUFFER_USAGE_STORAGE_BUFFER_BIT
                    | VK_BUFFER_USAGE_TRANSFER_SRC_BIT
                    | VK_BUFFER_USAGE_TRANSFER_DST_BIT,
                host_vis,
            )?;
            self.prefill_hidden_mapped_ptr = self.ctx.map_buffer_persistent(&buf)?;
            self.prefill_hidden_capacity = bytes;
            self.prefill_hidden_buf = Some(buf);
        }
        Ok(())
    }

    unsafe fn ensure_prefill_hidden_buffer_preserving_contents(
        &mut self,
        bytes: usize,
        host_vis: VkFlags,
    ) -> Result<(), String> {
        if self.prefill_hidden_capacity >= bytes {
            return Ok(());
        }
        let old_len = self.prefill_hidden_capacity;
        let old = if old_len > 0 && !self.prefill_hidden_mapped_ptr.is_null() {
            let mut old = vec![0u8; old_len];
            ptr::copy_nonoverlapping(self.prefill_hidden_mapped_ptr, old.as_mut_ptr(), old_len);
            old
        } else {
            Vec::new()
        };
        self.ensure_prefill_hidden_buffer(bytes, host_vis)?;
        if !old.is_empty() {
            ptr::copy_nonoverlapping(old.as_ptr(), self.prefill_hidden_mapped_ptr, old.len());
        }
        Ok(())
    }

    unsafe fn ensure_attention_cache_layer_buffers(
        &mut self,
        layer_idx: usize,
        kv_bytes: usize,
        host_vis: VkFlags,
    ) -> Result<(), String> {
        let needs_realloc = match self.attention_cache_layers.get(&layer_idx) {
            Some(layer) => layer.k_capacity < kv_bytes || layer.v_capacity < kv_bytes,
            None => true,
        };
        if !needs_realloc {
            return Ok(());
        }
        let allocation_bytes = attention_cache_allocation_bytes(kv_bytes)?;
        let old = self.attention_cache_layers.remove(&layer_idx);
        let k_buf = self.ctx.create_buffer(
            allocation_bytes as u64,
            VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
            host_vis,
        )?;
        let k_mapped_ptr = self.ctx.map_buffer_persistent(&k_buf)?;
        let v_buf = self.ctx.create_buffer(
            allocation_bytes as u64,
            VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
            host_vis,
        )?;
        let v_mapped_ptr = self.ctx.map_buffer_persistent(&v_buf)?;
        if let Some(old) = old {
            let copy_bytes = old.k_capacity.min(kv_bytes);
            if copy_bytes > 0 {
                ptr::copy_nonoverlapping(old.k_mapped_ptr, k_mapped_ptr, copy_bytes);
                ptr::copy_nonoverlapping(old.v_mapped_ptr, v_mapped_ptr, copy_bytes);
            }
            self.ctx.unmap_buffer(&old.k_buf);
            self.ctx.unmap_buffer(&old.v_buf);
            self.ctx.destroy_buffer(old.k_buf);
            self.ctx.destroy_buffer(old.v_buf);
        }
        self.attention_cache_layers.insert(
            layer_idx,
            AttentionCacheLayer {
                k_buf,
                k_mapped_ptr,
                k_capacity: allocation_bytes,
                v_buf,
                v_mapped_ptr,
                v_capacity: allocation_bytes,
            },
        );
        Ok(())
    }

    pub(crate) fn ensure_attention_cache_layer_buffers_for_fullpath(
        &mut self,
        layer_idx: usize,
        num_kv_heads: usize,
        kv_len: usize,
        head_dim: usize,
    ) -> Result<(), String> {
        if num_kv_heads == 0 || kv_len == 0 || head_dim == 0 {
            return Err(format!(
                "ensure_attention_cache_layer_buffers_for_fullpath: num_kv_heads/kv_len/head_dim \
                 must be > 0 (num_kv_heads={} kv_len={} head_dim={})",
                num_kv_heads, kv_len, head_dim
            ));
        }
        let reserve_kv_len = kv_len.max(self.fullpath_staging_capacity.max_seq_len as usize);
        let kv_bytes = reserve_kv_len
            .checked_mul(head_dim)
            .and_then(|x| x.checked_mul(std::mem::size_of::<f32>()))
            .ok_or("ensure_attention_cache_layer_buffers_for_fullpath: kv buffer size overflow")?;
        unsafe {
            let host_vis =
                VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | VK_MEMORY_PROPERTY_HOST_COHERENT_BIT;
            for kvh in 0..num_kv_heads {
                self.ensure_attention_cache_layer_buffers(
                    layer_idx * 100 + kvh,
                    kv_bytes,
                    host_vis,
                )?;
            }
        }
        Ok(())
    }

    unsafe fn ensure_gdn_conv_state_layer_buffer(
        &mut self,
        layer_idx: usize,
        state_bytes: usize,
        host_vis: VkFlags,
    ) -> Result<(), String> {
        let needs_realloc = match self.gdn_conv_state_layers.get(&layer_idx) {
            Some(layer) => layer.capacity < state_bytes,
            None => true,
        };
        if !needs_realloc {
            return Ok(());
        }
        let old = self.gdn_conv_state_layers.remove(&layer_idx);
        let buf = self.ctx.create_buffer(
            state_bytes as u64,
            VK_BUFFER_USAGE_STORAGE_BUFFER_BIT
                | VK_BUFFER_USAGE_TRANSFER_SRC_BIT
                | VK_BUFFER_USAGE_TRANSFER_DST_BIT,
            host_vis,
        )?;
        let mapped_ptr = self.ctx.map_buffer_persistent(&buf)?;
        ptr::write_bytes(mapped_ptr, 0, state_bytes);
        if let Some(old) = old {
            let copy_bytes = old.capacity.min(state_bytes);
            if copy_bytes > 0 {
                ptr::copy_nonoverlapping(old.mapped_ptr, mapped_ptr, copy_bytes);
            }
            self.ctx.unmap_buffer(&old.buf);
            self.ctx.destroy_buffer(old.buf);
        }
        self.gdn_conv_state_layers.insert(
            layer_idx,
            GdnConvStateLayer {
                buf,
                mapped_ptr,
                capacity: state_bytes,
            },
        );
        Ok(())
    }

